thai_sarcasm.process_docs:
def process_docs(dataset: datasets.Dataset) -> datasets.Dataset:
    def _add_gold(doc):
        doc["gold"] = 1 if str(doc.get("label", "")).strip() in ("1", "1.0") else 0
        doc["text"] = str(doc.get("text", "")).strip()
        return doc
    return dataset.map(_add_gold)

